const url = $input.first().json.body?.url || $input.first().json.url;
if (!url || !url.includes('youtube.com') && !url.includes('youtu.be')) {
  throw new Error('Invalid YouTube URL');
}
return [{ json: { url } }];

const info = $('Get Video Info').first().json;
const title = info.title || 'untitled';
const slug = title.toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').substring(0, 60);
const date = new Date().toISOString().split('T')[0];
const folderName = `${date}_${slug}`;
return [{ json: {
  folderName, slug, date,
  metadata: {
    title: title.replace(/'/g, "'"),
    channel: info.channel || info.uploader || '',
    channelUrl: info.channel_url || info.uploader_url || '',
    publishDate: info.upload_date || '',
    duration: info.duration || 0,
    durationFormatted: new Date((info.duration || 0) * 1000).toISOString().substr(11, 8),
    description: (info.description || '').substring(0, 1000),
    viewCount: info.view_count || 0,
    youtubeUrl: $('Validate URL').first().json.url,
    thumbnailUrl: info.thumbnail || ''
  }
}}];

const transcript = $('Fetch Transcript').first().json.data?.transcript;
const meta = $('Build Metadata').first().json.metadata;
const folderName = $('Build Metadata').first().json.folderName;
if (!transcript) throw new Error('Transcript not ready — increase wait time');
const sentences = transcript.sentences || [];
const formatTime = (ms) => {
  const totalSec = Math.floor((ms || 0) / 1000);
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  const s = totalSec % 60;
  return h > 0 ? `${h}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}` : `${m}:${String(s).padStart(2,'0')}`;
};
let body = '';
let curSpeaker = '';
sentences.forEach(s => {
  if (s.speaker_name !== curSpeaker) {
    curSpeaker = s.speaker_name;
    body += `\n\n**${curSpeaker || 'Speaker'}** \`[${formatTime(s.start_time)}]\`\n`;
  }
  body += s.text + ' ';
});
const md = `---
title: "${meta.title}"
channel: "${meta.channel}"
channel_url: "${meta.channelUrl}"
youtube_url: "${meta.youtubeUrl}"
publish_date: "${meta.publishDate}"
duration: "${meta.durationFormatted}"
view_count: ${meta.viewCount}
transcribed_at: "${new Date().toISOString()}"
folder: "${folderName}"
---

# ${meta.title}

> **Channel:** ${meta.channel}  
> **Published:** ${meta.publishDate}  
> **Duration:** ${meta.durationFormatted}  
> **Source:** ${meta.youtubeUrl}

---

## Transcript
${body.trim()}
`;
return [{ json: { transcriptMd: md, folderName, meta, summary: transcript.summary, sentences } }];

