const raw = $('Extract Insights').first().json;
const content = raw.choices?.[0]?.message?.content || '{}';
let insights;
try { insights = JSON.parse(content.replace(/```json|```/g, '').trim()); }
catch(e) { insights = { key_points: [], winning_quotes: [], themes: [], one_liner: '' }; }
const summary = $('Build Transcript MD').first().json.summary;
const meta = $('Build Transcript MD').first().json.meta;
const folderName = $('Build Transcript MD').first().json.folderName;
const kp = insights.key_points?.map(p => `- ${p}`).join('\n') || '';
const quotes = insights.winning_quotes?.map(q => `> "${q.quote}"\n> — ${q.speaker || 'Unknown'}${q.context ? ` *(${q.context})*` : ''}`).join('\n\n') || '';
const themes = insights.themes?.map(t => `\`${t}\``).join(' · ') || '';
const kws = Array.isArray(summary?.keywords) ? summary.keywords.map(k => `\`${k}\``).join(' ') : '';
const summaryMd = `---
title: "${meta.title}"
channel: "${meta.channel}"
youtube_url: "${meta.youtubeUrl}"
generated_at: "${new Date().toISOString()}"
---

# Summary: ${meta.title}

> ${insights.one_liner || summary?.overview || ''}

**Channel:** ${meta.channel}  
**Published:** ${meta.publishDate}  
**Duration:** ${meta.durationFormatted}  
${themes ? `**Themes:** ${themes}` : ''}

---

## Key Points

${kp}

---

## Winning Quotes

${quotes}

---

## Overview

${summary?.overview || ''}

${summary?.bullet_gist ? `## Bullet Points\n\n${summary.bullet_gist}` : ''}

${kws ? `---\n\n**Keywords:** ${kws}` : ''}
`;
const metaJson = JSON.stringify({
  title: meta.title, channel: meta.channel, channelUrl: meta.channelUrl,
  youtubeUrl: meta.youtubeUrl, publishDate: meta.publishDate,
  duration: meta.durationFormatted, durationSeconds: meta.duration,
  viewCount: meta.viewCount, thumbnailUrl: meta.thumbnailUrl,
  description: meta.description, themes: insights.themes || [],
  keywords: summary?.keywords || [], transcribedAt: new Date().toISOString(),
  folderPath: `transcripts/${folderName}`
}, null, 2);
return [{ json: { summaryMd, metaJson, folderName, transcriptMd: $('Build Transcript MD').first().json.transcriptMd } }];

const folder = $('Build Summary MD').first().json.folderName;
const base = 'https://github.com/DeveloperAlly/ai-and-agents/blob/main/transcripts';
return [{ json: {
  success: true, folder,
  files: {
    transcript: `${base}/${folder}/transcript.md`,
    summary: `${base}/${folder}/summary.md`,
    metadata: `${base}/${folder}/metadata.json`,
    audio: `${base}/${folder}/audio.mp3`
  },
  message: `Transcription complete for: ${$('Build Metadata').first().json.metadata.title}`
}}];
